sql:
SELECT images.image_id, images.source_image, performance_metrics.processing_time AS processing_time
FROM images
JOIN performance_metrics ON images.image_id = performance_metrics.image_id;

SELECT images.source_image, errors.error_message, errors.timestamp
FROM images
INNER JOIN errors ON images.image_id = errors.image_id;

SELECT output_format, AVG(width) AS avg_width, AVG(height) AS avg_height
FROM images
GROUP BY output_format;

external_knowledge:
- 'treasure chest of images' refers to the image library with the name 'Your Library Name';
- 'identities' refers to the unique identifiers of the images (image_id);
- 'sources' refers to the source name/path of the images (source_image);
- 'average resource utilizations' refers to the average processing time, memory usage, and CPU usage for each image.

sql:
SELECT image_id, AVG(quality) as average_quality
FROM image_settings
GROUP BY image_id;
